  p_Feedback_8c023119 TEXT;
  p_Status_8c023119 VARCHAR(15);
  p_QualityRank_8c023119 INTEGER;
  p_ExecutionCostRank_8c023119 INTEGER;
  p_UsesTemplate_8c023119 BOOLEAN;
  p_AuditQueryRuns_8c023119 BOOLEAN;
  p_CacheEnabled_8c023119 BOOLEAN;
  p_CacheTTLMinutes_8c023119 INTEGER;
  p_CacheMaxSize_8c023119 INTEGER;
  p_EmbeddingVector_8c023119 TEXT;
  p_EmbeddingModelID_8c023119 UUID;
  p_CacheValidationSQL_8c023119 TEXT;
  p_SQLDialectID_8c023119 UUID;
  p_Reusable_8c023119 BOOLEAN;
BEGIN
  p_ID_8c023119 := 'F3D2A1B8-9C4E-4E7A-BCDE-1234567ABCDE';
  p_Name_8c023119 := 'ListConversationDetailFeedbackStats';
  p_CategoryID_8c023119 := '5FB6FAFF-8904-490D-9BEE-CA1FF906BD44';
  p_UserQuestion_8c023119 := 'What are the aggregate counts and average for conversation feedback ratings (matching the same filters as the row-level query)?';
  p_Description_8c023119 := 'Aggregate companion for ListConversationDetailFeedback. Returns Total, AvgRating, PositiveCount (>=8), and NegativeCount (<=3) over the same filtered universe (StartDate, EndDate, MinRating, MaxRating, AgentID, SearchText). Used by the Agent Feedback admin page to populate the four stat cards.';
  p_SQL_8c023119 := '-- Aggregate stats matching the same filter universe as
-- ListConversationDetailFeedback (the row-level query). Used by the Agent
-- Feedback resource to populate the four stat cards (Total / Avg / %High /
-- %Low) — those need to reflect ALL filtered rows, not just the current page,
-- which is why this lives in a separate query rather than being denormalised
-- onto every paged row.
--
-- Parameters mirror the row query (StartDate, EndDate, MinRating, MaxRating,
-- AgentID, SearchText) — pass identical values so both queries describe the
-- same filtered set.
SELECT
    COUNT(*)                                                              AS Total,
    AVG(CAST(cd."UserRating" AS FLOAT))                                     AS AvgRating,
    SUM(CASE WHEN cd."UserRating" >= 8 THEN 1 ELSE 0 END)                   AS PositiveCount,
    SUM(CASE WHEN cd."UserRating" <= 3 THEN 1 ELSE 0 END)                   AS NegativeCount
FROM [__mj].ConversationDetail cd
LEFT JOIN [__mj].Conversation   c  ON c."ID"  = cd."ConversationID"
LEFT JOIN [__mj].[User]         cu ON cu."ID" = c."UserID"
LEFT JOIN [__mj].AIAgent        a  ON a."ID"  = cd."AgentID"
WHERE cd."UserRating" IS NOT NULL
    {% if StartDate %}
    AND cd.__mj_UpdatedAt >= {{ StartDate | sqlString }}
    {% endif %}
    {% if EndDate %}
    AND cd.__mj_UpdatedAt <= {{ EndDate | sqlString }}
    {% endif %}
    {% if MinRating %}
    AND cd."UserRating" >= {{ MinRating }}
    {% endif %}
    {% if MaxRating %}
    AND cd."UserRating" <= {{ MaxRating }}
    {% endif %}
    {% if AgentID %}
    AND cd."AgentID" = {{ AgentID | sqlString }}
    {% endif %}
    {% if SearchText %}
    AND (
            cd."UserFeedback"   LIKE {{ SearchText | sqlLikeContains }}
         OR cd."Message"        LIKE {{ SearchText | sqlLikeContains }}
         OR a."Name"            LIKE {{ SearchText | sqlLikeContains }}
         OR cu."Name"           LIKE {{ SearchText | sqlLikeContains }}
         OR cu."Email"          LIKE {{ SearchText | sqlLikeContains }}
    )
    {% endif %}
';
  p_TechnicalDescription_8c023119 := 'Single aggregate SELECT against __mj."ConversationDetail" WHERE UserRating IS NOT NULL with the same LEFT JOINs and Nunjucks filter blocks as ListConversationDetailFeedback. Returns four scalars in a single row.';
  p_Status_8c023119 := 'Approved';
  p_QualityRank_8c023119 := 8;
  p_ExecutionCostRank_8c023119 := 1;
  p_UsesTemplate_8c023119 := TRUE;
  p_AuditQueryRuns_8c023119 := FALSE;
